using Expenses.Domain; using Microsoft.EntityFrameworkCore;
namespace Expenses.Persistence.Seed; /** <summary>Expense seeder.</summary> */ public static class ExpensesSeeder {/** <summary>Seeds demo rows once.</summary> */ public static async Task SeedAsync(ExpensesDbContext db,CancellationToken ct){if(await db.Expenses.AnyAsync(ct))return;string[] categories=["مواد خام","رواتب","صيانة","نقل","مرافق"];for(var i=0;i<30;i++)db.Expenses.Add(Expense.Create(categories[i%categories.Length],500+(i*125),DateOnly.FromDateTime(DateTime.UtcNow.Date).AddMonths(-(i%6)).AddDays(-(i%20)),$"مستفيد {i+1}",$"مصروف تجريبي {i+1}").Value);await db.SaveChangesAsync(ct);}}
